import{_ as l,c as n,o as a,ah as o}from"./chunks/framework.OstmDACS.js";const m=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"docs/Robotics/Planning/1intro.md","filePath":"docs/Robotics/Planning/1intro.md","lastUpdated":1779451857000}'),t={name:"docs/Robotics/Planning/1intro.md"};function e(r,i,s,u,c,d){return a(),n("div",null,i[0]||(i[0]=[o('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h1><blockquote><p>Source：<a href="https://github.com/liuxinren456852/Motion-plan" target="_blank" rel="noreferrer"><em>Motion Planning for Mobile Robots</em> from Shenlan Course by Fei Gao uploaded in Github</a> before 2019</p></blockquote><h2 id="definition" tabindex="-1">Definition <a class="header-anchor" href="#definition" aria-label="Permalink to “Definition”">​</a></h2><h3 id="autonomous-robot" tabindex="-1">Autonomous Robot <a class="header-anchor" href="#autonomous-robot" aria-label="Permalink to “Autonomous Robot”">​</a></h3><p>An autonomous robot is a robot that performs behaviors or tasks with a high degree of autonomy (without external influence).</p><p>Sensing-Localization &amp; Mapping-Planning-Control action loop</p><ul><li><strong>Estimation</strong>: <ul><li>Low latency</li><li>High accuracy &amp; consistency</li></ul></li><li><strong>Perception</strong>: <ul><li>3D sensing &amp; dense perception</li><li>Map fusion &amp; integration for planning</li></ul></li><li><strong>Planning</strong>: <ul><li>Complex &amp; unknown environments</li><li>Safety &amp; dynamical feasibility</li><li>Limited sensing &amp; computation</li></ul></li><li><strong>Control</strong>: <ul><li>Aggressive maneuvers</li><li>Smooth trajectory tracking</li></ul></li></ul><h3 id="motion-planning" tabindex="-1">Motion Planning <a class="header-anchor" href="#motion-planning" aria-label="Permalink to “Motion Planning”">​</a></h3><ul><li>Basic requirements: <ul><li>Safety: collision avoidance</li><li>Smoothness: energy saving, comfort</li><li>Kinodynamic feasibility: executable, controllable</li></ul></li><li>Old-school pipeline: <ul><li>Front-end path finding: <ul><li>Search for an initial safety path</li><li>Low dimensional</li><li>Discrete space</li></ul></li><li>Back-end trajectory generation: <ul><li>Search for an executable trajectory</li><li>High dimensional</li><li>Continuous space</li></ul></li></ul></li></ul><h2 id="outline-of-motion-planning" tabindex="-1">Outline of motion planning <a class="header-anchor" href="#outline-of-motion-planning" aria-label="Permalink to “Outline of motion planning”">​</a></h2><p>Front-end: <strong>Path finding</strong></p><ul><li>SEARCH-BASED PATH FINDING <ul><li>Graph Search Basis</li><li>Dijkstra and A*</li><li>Jump Point Search</li></ul></li><li>SAMPLING-BASED PATH FINDING <ul><li>Probabilistic Road Map</li><li>Rapidly-exploring Random Tree (RRT)</li><li>Optimal Sampling-based Methods</li><li>Advanced Sampling-based Methods</li></ul></li><li>KINODYNAMIC PATH FINDING <ul><li>Introduction</li><li>State-state Boundary Value Optimal Control Problem</li><li>State Lattice Search</li><li>Kinodynamic RRT*</li><li>Hybrid A*</li></ul></li></ul><p>Back-end: Trajectory Generation</p><ul><li>MINIMUM SNAP TRAJECTORY GENERATION <ul><li>Differential Flatness</li><li>Minimum Snap Optimization</li><li>Closed-form Solution to Minimum Snap</li><li>Time Allocation</li><li>Implementation in Practice</li></ul></li><li>SOFT AND HARD CONSTRAINED TRAJECTORY OPTIMIZATION <ul><li>Soft Constrained Trajectory Optimization</li><li>Hard Constrained Trajectory Optimization</li></ul></li></ul><p>MDP &amp; MPC</p><ul><li>MARKOV DECISION PROCESS-BASED PLANNING <ul><li>Uncertainties in Planning and MDP</li><li>Minimax Cost Planning and Expected Cost Minimal Planning</li><li>Value Iteration and Real-Time Dynamic Programming</li></ul></li><li>MODEL PREDICTIVE CONTROL FOR ROBOTICS PLANNING <ul><li>Introduction</li><li>Linear MPC</li><li>Non-linear MPC</li></ul></li></ul><h2 id="map-representation" tabindex="-1">map Representation <a class="header-anchor" href="#map-representation" aria-label="Permalink to “map Representation”">​</a></h2><p>Consists of two parts: <strong>Data Structure</strong> and <strong>Fusion Method</strong>.</p><ul><li>Occupancy Grid Map <ul><li>Most dense</li><li>Structural</li><li>Direct Index Query</li></ul></li><li>Octo-map <ul><li>Sparse</li><li>Structural</li><li>Indirect Index Query</li></ul></li><li>Voxel hashing <ul><li>Most Sparse</li><li>Structural</li><li>Indirect Index Query</li></ul></li><li>Point Cloud Map <ul><li>Un-ordered</li><li>No Index Query</li></ul></li><li>TSDF (Truncated Signed Distance Functions) map</li><li>ESDF (Euclidean Signed Distance Functions) map <ul><li>Incremental update, global map</li><li>Batch update, local map</li></ul></li><li>More: <ul><li>Free-space roadmap</li><li>Voronoi diagram map</li></ul></li></ul>',19)]))}const h=l(t,[["render",e]]);export{m as __pageData,h as default};
